// Complete executable Python solution file that reads from sys.stdin, calls Solution.detect_cycle, and prints output.
import sys

class Solution:
  def solve(self):
    n = int(sys.stdin.readline())
    edges = []
    for _ in range(n):
      m = int(sys.stdin.readline())
      for _ in range(m):
        u, v = map(int, sys.stdin.readline().split())
        edges.append([u, v])
    g = Graph(n)
    for edge in edges:
      g.add_edge(edge[0], edge[1])
    print("true" if g.detect_cycle(n, edges) else "false")

if __name__ == '__main__':
  t = int(sys.stdin.readline())
  for _ in range(t):
    Solution().solve()

